 6→internal actual class AbortFlowException actual constructor(
 7→    @JvmField @Transient actual val owner: FlowCollector<*>
 8→) : CancellationException("Flow was aborted, no more elements needed") {
 9→
10→    override fun fillInStackTrace(): Throwable {
11→        if (DEBUG) return super.fillInStackTrace()
12→        // Prevent Android <= 6.0 bug, #1866
13→        stackTrace = emptyArray()
14→        return this
15→    }
16→}
