19→    override fun fillInStackTrace(): Throwable {
20→        if (DEBUG) return super.fillInStackTrace()
21→        // Prevent Android <= 6.0 bug, #1866
22→        stackTrace = emptyArray()
23→        return this
24→    }
25→}
